        event_constraints: Vec<Loc<OrderConstraint<Time>>>,
        sig_bindings: Vec<Loc<ParamBind>>,
    ) -> Self {
        let outputs_idx = inputs.len();
        inputs.append(&mut outputs);
        Self {
            name,
            params,
            sig_bindings,
