impl DisplayCtx<ir::Port> for ir::Component {
    fn display(&self, idx: ir::PortIdx) -> String {
        let port = self.get(idx);
        let name = self
            .get(port.info)
            .as_port()
            .map_or(format!("{idx}"), |p| format!("{}", p.name));
        match port.owner {
            ir::PortOwner::Local | ir::PortOwner::Sig { .. } => name,
