pub struct IndexStore<T, I = utils::Idx<T>>
where
    I: utils::IdxLike<T>,
{
    store: Vec<T>,
    /// Tracks which indices have been marked invalid.
    valid: BitVec,
    /// The kind of index used to access the store.
    _type: PhantomData<I>,
}

impl<T> Default for IndexStore<T> {
